// ================================================================
// LinkUp WF-4 - Refine a draft on demand.
// The extension sends the current draft + a plain-English change
// request; this rewrites the message in Sagnik's voice and returns it.
// Powered by Haiku 4.5 (cheap, fast, plenty for targeted edits).
// ================================================================
const payload = $json.body || $json || {};

// ---------- Security ----------
if (payload.secret !== $env.LINKUP_SECRET) {
  return [{ json: { ok: false, error: 'Unauthorized' } }];
}

const draft = String(payload.draft || '').trim();
const instruction = String(payload.instruction || '').trim();
const context = String(payload.context || '').slice(0, 1500);
if (!draft) {
  return [{ json: { ok: false, error: 'No draft to refine.' } }];
}
if (!instruction) {
  return [{ json: { ok: false, error: 'Type the change you want first.' } }];
}

const prompt = `You are refining a LinkedIn message that Sagnik (a job-seeking
BITS Pilani student) is about to send. Apply ONLY the change he asks for. Keep
his voice: natural, human, specific - no corporate fluff, no cliches, no
em-dash-heavy AI phrasing. Do not invent facts he did not state. Keep it about
the same length unless he explicitly asks to shorten or expand.

${context ? 'CONTEXT (who this is for):\n' + context + '\n\n' : ''}CURRENT MESSAGE:
"""
${draft}
"""

CHANGE SAGNIK WANTS:
${instruction}

Return ONLY the revised message text - no preamble, no surrounding quotes, no
explanation.`;

const res = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': $env.ANTHROPIC_API_KEY,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json',
  },
  body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 700,
    messages: [{ role: 'user', content: prompt }],
  },
  json: true,
});

const revised = ((((res || {}).content || [])[0] || {}).text || '').trim();
if (!revised) {
  return [{ json: { ok: false, error: 'Got an empty rewrite - try rephrasing the change.' } }];
}
return [{ json: { ok: true, message: revised } }];
